#include <stdio.h>

int main() {
    // Declaration and initialization
    int arr[5] = {10, 20, 30, 40, 50};

    // Accessing elements using index
    printf("First element: %d\n", arr[0]);  // Output: 10
    printf("Third element: %d\n", arr[2]);  // Output: 30

    // Modifying an element
    arr[1] = 25;
    printf("Modified second element: %d\n", arr[1]);  // Output: 25

    // Traversing the array
    printf("All elements: ");
    for(int i = 0; i < 5; i++) {
        printf("%d ", arr[i]);
    }
    // Output: 10 25 30 40 50

    return 0;
}

public class ArrayBasics {
    public static void main(String[] args) {
        // Declaration and initialization
        int[] arr = {10, 20, 30, 40, 50};

        // Alternative declaration
        int[] arr2 = new int[5];  // Default values: 0

        // Accessing elements
        System.out.println("First: " + arr[0]);  // Output: 10
        System.out.println("Length: " + arr.length);  // Output: 5

        // Modifying
        arr[1] = 25;

        // Traversing with for-each
        System.out.print("Elements: ");
        for(int element : arr) {
            System.out.print(element + " ");
        }
        // Output: 10 25 30 40 50

        // Traversing with index
        for(int i = 0; i < arr.length; i++) {
            System.out.println("arr[" + i + "] = " + arr[i]);
        }
    }
}
